SELECT COUNT(*) AS active_certificate_count
FROM certificates
WHERE status = 'active';

SELECT COUNT(access_id) AS total_accesses
FROM certificate_access
WHERE user_id = 1;

SELECT COUNT(*) AS renewal_count
FROM certificate_lifecycle
WHERE event_type = 'Renewal';

SELECT tag_name
FROM certificate_tags
WHERE certificate_id = '1';

SELECT COUNT(tag_id) AS tag_count
FROM certificate_tags
WHERE certificate_id = '1';

SELECT COUNT(DISTINCT tag_name) AS unique_tag_count
FROM certificate_tags
WHERE certificate_id = '1';
